import type { Recipe } from '../../../types/api'
import { ModalWidget } from '../../../utils/modal'

/**
 * Options for creating a MoveModal
 */
export interface MoveModalOptions {
  /** Callback when a single recipe is moved to a different slot (handles reordering) */
  onMoveRecipe: (recipeIndex: number, targetSlotLabel: string) => Promise<void>
}

/**
 * MoveModal handles the UI for moving a recipe to a different slot.
 * It displays available slots as CTA buttons; selecting a different slot
 * and closing the modal triggers the move operation (deferred move).
 */
export class MoveModal {
  private container: HTMLElement
  private modal: ModalWidget | null = null
  private options: MoveModalOptions
  private currentRecipeIndex: number = -1
  private selectedSlotLabel: string | null = null
  private originalSlotLabel: string | null = null

  constructor(options: MoveModalOptions) {
    this.container = document.createElement('div')
    document.body.appendChild(this.container)
    this.options = options
  }

  /**
   * Opens the move modal for a specific recipe
   */
  open(recipe: Recipe, recipeIndex: number, slotLabels: string[]): void {
    // Destroy existing modal if any
    this.modal?.destroy()

    this.currentRecipeIndex = recipeIndex
    this.originalSlotLabel = recipe.slot_label
    this.selectedSlotLabel = recipe.slot_label

    this.modal = new ModalWidget(this.container, {
      content: () => this.createContent(recipe, slotLabels),
      onClose: () => {
        // Deferred move: fire onMoveRecipe if selection changed
        if (this.selectedSlotLabel && this.selectedSlotLabel !== this.originalSlotLabel) {
          this.options.onMoveRecipe(this.currentRecipeIndex, this.selectedSlotLabel).catch(error => {
            console.error('Failed to move recipe:', error)
          })
        }
        this.modal = null
      }
    })

    this.modal.render()
    this.modal.openModal()
  }

  /**
   * Closes the modal
   */
  close(): void {
    this.modal?.closeModal('button')
  }

  /**
   * Destroys the modal and removes its container from the DOM
   */
  destroy(): void {
    this.modal?.destroy()
    this.container.remove()
  }

  /**
   * Creates the modal content with slot selection buttons
   * Uses 2-column layout for m+ (>= 768px)
   */
  private createContent(recipe: Recipe, slotLabels: string[]): HTMLElement {
    const container = document.createElement('div')
    container.className = 'miso-move-modal'

    const isMPlus = window.matchMedia('(min-width: 768px)').matches

    if (isMPlus) {
      // Left column with recipe preview
      const leftColumn = document.createElement('div')
      leftColumn.className = 'miso-move-modal__left-column'

      const modalName = document.createElement('div')
      modalName.className = 'miso-move-modal__name'
      modalName.textContent = 'QUICK MOVE'
      leftColumn.appendChild(modalName)

      const title = document.createElement('h2')
      title.className = 'miso-move-modal__title'
      title.textContent = recipe.title
      leftColumn.appendChild(title)

      // Recipe preview card
      const previewCard = document.createElement('div')
      previewCard.className = 'miso-modal__recipe-preview'

      const previewImage = document.createElement('img')
      previewImage.className = 'miso-modal__recipe-preview-image'
      previewImage.src = recipe.cover_image || ''
      previewImage.alt = recipe.title
      previewImage.onerror = () => {
        previewImage.style.backgroundColor = 'rgba(0, 0, 0, 0.15)'
        previewImage.style.display = 'block'
      }
      previewCard.appendChild(previewImage)

      const previewTitle = document.createElement('div')
      previewTitle.className = 'miso-modal__recipe-preview-title'
      previewTitle.textContent = recipe.title
      previewCard.appendChild(previewTitle)

      leftColumn.appendChild(previewCard)
      container.appendChild(leftColumn)

      // Right column with slots
      const rightColumn = document.createElement('div')
      rightColumn.className = 'miso-move-modal__right-column'

      const slotsContainer = document.createElement('div')
      slotsContainer.className = 'miso-move-modal__slots'

      slotLabels.forEach(slotLabel => {
        const slotItem = this.createSlotItem(slotLabel)
        slotsContainer.appendChild(slotItem)
      })

      rightColumn.appendChild(slotsContainer)
      container.appendChild(rightColumn)
    } else {
      // Mobile layout
      const modalName = document.createElement('div')
      modalName.className = 'miso-move-modal__name'
      modalName.textContent = 'QUICK MOVE'
      container.appendChild(modalName)

      const title = document.createElement('h2')
      title.className = 'miso-move-modal__title'
      title.textContent = recipe.title
      container.appendChild(title)

      const slotsContainer = document.createElement('div')
      slotsContainer.className = 'miso-move-modal__slots'

      slotLabels.forEach(slotLabel => {
        const slotItem = this.createSlotItem(slotLabel)
        slotsContainer.appendChild(slotItem)
      })

      container.appendChild(slotsContainer)
    }

    return container
  }

  private createSlotItem(slotLabel: string): HTMLElement {
    const slotItem = document.createElement('button')
    slotItem.className = 'miso-cta-btn miso-cta-btn--regular miso-move-modal__slot-item'

    const isSelected = slotLabel === this.selectedSlotLabel
    if (isSelected) {
      slotItem.classList.add('miso-cta-btn--active')
    }

    slotItem.textContent = slotLabel

    slotItem.addEventListener('click', () => {
      this.selectedSlotLabel = slotLabel

      // Toggle active class on all slot items
      const allSlots = this.container.querySelectorAll('.miso-move-modal__slot-item')
      allSlots.forEach(slot => {
        slot.classList.remove('miso-cta-btn--active')
      })
      slotItem.classList.add('miso-cta-btn--active')
    })

    return slotItem
  }
}

